// REQUIRED Package.swift pattern for AudioKit scaffolds:
let package = Package(
    name: "MyApp",
    platforms: [.macOS(.v14)],
    dependencies: [
        .package(url: "https://github.com/AudioKit/AudioKit.git", from: "5.6.0"),
        .package(url: "https://github.com/AudioKit/AudioKitUI.git", from: "0.3.0"),
        .package(url: "https://github.com/AudioKit/SoundpipeAudioKit.git", from: "5.6.0")
    ],
    targets: [
        .executableTarget(
            name: "MyApp",
            dependencies: [
                .product(name: "AudioKit", package: "AudioKit"),
                .product(name: "AudioKitUI", package: "AudioKitUI"),
                .product(name: "SoundpipeAudioKit", package: "SoundpipeAudioKit")
            ]
        )
    ]
)

// CORRECT (AudioKit 5.x):
import AudioKit
import SoundpipeAudioKit

let osc = DynamicOscillator()
let table = Table(.sawtooth)
let oscWithTable = Oscillator(waveform: Table(.sawtooth))
let reverb = Reverb(osc)
let mixer = Mixer(osc1, osc2)
let engine = AudioEngine()  // NOT AKEngine

// WRONG (AudioKit 4.x — removed):
let osc = AKOscillator(waveform: AKTable(.sawtooth))  // cannot find 'AKOscillator' in scope
let reverb = AKReverb()                                 // cannot find 'AKReverb' in scope
let engine = AKEngine()                                 // cannot find 'AKEngine' in scope

// CORRECT (layout B):
// Package.swift: .executableTarget(name: "AudioKitMIDISynth", path: "Sources/AudioKitMIDISynth")
// Files:
//   Sources/AudioKitMIDISynth/AudioKitMIDISynthApp.swift
//   Sources/AudioKitMIDISynth/ContentView.swift
//   Sources/AudioKitMIDISynth/SynthConductor.swift

// WRONG (mixed):
// Package.swift: .executableTarget(name: "AudioKitMIDISynth", path: "Sources/AudioKitMIDISynth")
// Files:
//   Sources/AudioKitMIDISynth/App.swift  ← under custom path: OK
//   Sources/ContentView.swift            ← stranded! NOT under custom path → SPM error

// CORRECT (AudioKit 5.x):
let osc = DynamicOscillator()
let reverb = Reverb(osc)            // ← effect wraps source
let delay = Delay(reverb)           // ← chain by wrapping
engine.output = delay

// Multiple sources via Mixer:
let mixer = Mixer(osc1, osc2)
let reverb = Reverb(mixer)
engine.output = reverb

// WRONG (AudioKit 4.x syntax — removed):
engine.output = osc >>> reverb >>> delay   // cannot find operator '>>>' in scope

// CORRECT:
let osc = DynamicOscillator()
let reverb = Reverb(osc)
reverb.dryWetMix = 0.5
engine.output = reverb

// WRONG:
let reverb = Reverb()              // missing argument for parameter #1
reverb.input = osc                 // not how AudioKit works
